// Helper: render a preset to an SVG data URL string suitable for use as an
// extension icon ImageData / icon URL. Used by both the picker UI and by
// background.js when setting chrome.action.setIcon.
export function presetToSvgDataUrl(preset, size = 128) {
  const [c1, c2] = preset.bg;
  const fontSize = Math.round(size * 0.55);
  const radius = Math.round(size * 0.20);
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${size} ${size}">
    <defs><linearGradient id="g" x1="0" y1="0" x2="1" y2="1">
      <stop offset="0%" stop-color="${c1}"/><stop offset="100%" stop-color="${c2}"/>
    </linearGradient></defs>
    <rect width="${size}" height="${size}" rx="${radius}" fill="url(#g)"/>
    <text x="50%" y="50%" font-size="${fontSize}" text-anchor="middle" dominant-baseline="central" font-family="-apple-system, Segoe UI Emoji, sans-serif">${preset.emoji}</text>
  </svg>`;
  return 'data:image/svg+xml;utf8,' + encodeURIComponent(svg);
}

// DOM-based rasterizer (use in app page / popup — NOT service worker).
// SW's createImageBitmap can't decode SVG; this uses HTMLImageElement which can.
export function presetToImageDataDom(preset, size = 128) {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement('canvas');
      canvas.width = size; canvas.height = size;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(img, 0, 0, size, size);
      resolve(ctx.getImageData(0, 0, size, size));
    };
    img.onerror = (e) => reject(new Error('icon image load failed'));
    img.src = presetToSvgDataUrl(preset, size);
  });
}

// Build the full {16,32,48,128} ImageData bundle for chrome.action.setIcon.
export async function presetToIconBundle(preset) {
  const sizes = [16, 32, 48, 128];
  const bundle = {};
  for (const s of sizes) bundle[s] = await presetToImageDataDom(preset, s);
  return bundle;
}

// Same for a custom uploaded image data URL.
export function imageUrlToIconBundle(dataUrl) {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => {
      const sizes = [16, 32, 48, 128];
      const bundle = {};
      for (const s of sizes) {
        const canvas = document.createElement('canvas');
        canvas.width = s; canvas.height = s;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, s, s);
        bundle[s] = ctx.getImageData(0, 0, s, s);
      }
      resolve(bundle);
    };
    img.onerror = () => reject(new Error('image load failed'));
    img.src = dataUrl;
  });
}

// Original SW path (kept for back-compat — only works for raster sources, not SVG).
export async function presetToImageData(preset, size = 128) {
  const dataUrl = presetToSvgDataUrl(preset, size);
  const blob = await (await fetch(dataUrl)).blob();
  const bitmap = await createImageBitmap(blob);
  const canvas = new OffscreenCanvas(size, size);
  const ctx = canvas.getContext('2d');
  ctx.drawImage(bitmap, 0, 0, size, size);
  return ctx.getImageData(0, 0, size, size);
}
